const Formatter=window.Formatter={nvl:function(e,t=""){if(null==e)return t;const r=String(e).trim();return""===r?t:r},removeComma:function(e){return this.nvl(e).replace(/,/g,"")},number:function(e,t="0"){const r=this.removeComma(e);if(""===r)return t;const n=Number(r);return isNaN(n)?t:n.toLocaleString("ko-KR")},comma:function(e,t="0"){return this.number(e,t)},price:function(e){return this.number(e,"0")},decimal:function(e,t=2,r="0"){const n=this.removeComma(e);if(""===n)return r;const i=Number(n);return isNaN(i)?"0":i.toLocaleString("ko-KR",{minimumFractionDigits:t,maximumFractionDigits:t})},date:function(e,t="-"){if(!e)return"-";let r=String(e).replace(/[^0-9]/g,"");return 8===r.length?r.replace(/(\d{4})(\d{2})(\d{2})/,`$1${t}$2${t}$3`):6===r.length?r.replace(/(\d{4})(\d{2})/,`$1${t}$2`):e},dateTime:function(e,t="-",r=":"){if(!e)return"-";const n=String(e).replace(/[^0-9]/g,"");return n.length>=14?n.replace(/(\d{4})(\d{2})(\d{2})(\d{2})(\d{2})(\d{2}).*/,`$1${t}$2${t}$3 $4${r}$5${r}$6`):12===n.length?n.replace(/(\d{4})(\d{2})(\d{2})(\d{2})(\d{2})/,`$1${t}$2${t}$3 $4${r}$5`):this.date(e,t)},time:function(e,t=":"){if(!e)return"-";const r=String(e).replace(/[^0-9]/g,"");return r.length>=6?r.replace(/(\d{2})(\d{2})(\d{2}).*/,`$1${t}$2${t}$3`):4===r.length?r.replace(/(\d{2})(\d{2})/,`$1${t}$2`):e},phone:function(e){if(!e)return"-";let t=String(e).replace(/[^0-9]/g,"");return 11===t.length?t.replace(/(\d{3})(\d{4})(\d{4})/,"$1-$2-$3"):10===t.length?t.startsWith("02")?t.replace(/(\d{2})(\d{4})(\d{4})/,"$1-$2-$3"):t.replace(/(\d{3})(\d{3})(\d{4})/,"$1-$2-$3"):9===t.length&&t.startsWith("02")?t.replace(/(\d{2})(\d{3})(\d{4})/,"$1-$2-$3"):e},fileSize:function(e,t=1){const r=Number(e);if(!r||isNaN(r))return"0 B";const n=["B","KB","MB","GB","TB"],i=Math.min(Math.floor(Math.log(r)/Math.log(1024)),n.length-1);return`${(r/Math.pow(1024,i)).toFixed(0===i?0:t)} ${n[i]}`},percent:function(e,t,r=1){const n=Number(this.removeComma(e)),i=Number(this.removeComma(t));return isNaN(n)||isNaN(i)||0===i?"0":(n/i*100).toFixed(r).replace(/\.0+$/,"")},getByteLength:function(e){if(!e)return 0;let t=0;for(let r=0;r<e.length;r++){t+=e.charCodeAt(r)>127?3:1}return t},escapeHtml:function(e){return this.nvl(e).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;").replace(/'/g,"&#39;")},unescapeHtml:function(e){const t=document.createElement("textarea");return t.innerHTML=this.nvl(e),t.value}};